/**
 * Custom hook for fee calculation logic
 */

import { useState, useEffect } from 'react';
import { disbursementService } from '@/features/disbursements/services';
import { getChannelFromPaymentMethod } from '@/features/disbursements/utils/helpers.js';
import logger from '@/shared/utils/logger.js';

export const useFeeCalculation = (disbursementServiceId) => {
  const [feeData, setFeeData] = useState(null);
  const [isCheckingFee, setIsCheckingFee] = useState(false);

  const checkFee = async (amount, channel) => {
    if (!amount || !disbursementServiceId) {
      setFeeData(null);
      return false;
    }

    setIsCheckingFee(true);
    try {
      const response = await disbursementService.checkFullPayable({
        amount: amount.toString(),
        channel,
        serviceId: disbursementServiceId,
      });

      if (response.code === '00' && response.data) {
        setFeeData(response.data);
        return true;
      }

      setFeeData(null);
      return false;
    } catch (error) {
      logger.error('Failed to check fee:', { error });
      setFeeData(null);
      return false;
    } finally {
      setIsCheckingFee(false);
    }
  };

  return {
    feeData,
    setFeeData,
    isCheckingFee,
    checkFee,
  };
};

